    """Parse the inner string (JSON) into a dict with keys: ver, payload, checksum."""
    d = json.loads(data_str)
    # Ensure correct types
    return {
        "ver": int(d["ver"]),
        "payload": str(d["payload"]),
        "checksum": int(d["checksum"]),
    }


def compute_fluxon_checksum(payload: str, ver: int) -> int:
    """Compute correct checksum: sum of ordinals of payload modulo 256."""
    return sum(ord(c) for c in payload) % 256


