import json
import fnmatch

def _match_pattern(pattern: str, value: str) -> bool:
    """Check if a value matches a pattern (supports '*' and '?' wildcards)."""
    return fnmatch.fnmatch(value, pattern)

def _check_statement(statement: dict, subject: str, resource: str, action: str) -> bool:
    """Check if a single statement matches the given subject, resource, and action.
    The Effect field is ignored."""
    # Get action(s)
    actions = statement.get("Action", [])
    if isinstance(actions, str):
        actions = [actions]
    # Get resource(s)
    resources = statement.get("Resource", [])
    if isinstance(resources, str):
        resources = [resources]
    # Check action match
    action_match = any(_match_pattern(a, action) for a in actions)
    # Check resource match
    resource_match = any(_match_pattern(r, resource) for r in resources)
    # Subject is typically the principal; in many policies it's not part of the statement
    # but we can check a "Principal" field if it exists, otherwise ignore.
    # For simplicity, we assume subject is ignored (or we could check Principal).
    subject_match = True
    if "Principal" in statement:
        principals = statement["Principal"]
        if isinstance(principals, dict):
            # Common principal types: AWS, Federated, etc.
            # For simplicity, treat as a list of ARN strings or wildcard
            principal_values = []
            for key in principals:
                val = principals[key]
                if isinstance(val, str):
                    principal_values.append(val)
                elif isinstance(val, list):
                    principal_values.extend(val)
            subject_match = any(_match_pattern(p, subject) for p in principal_values)
        elif isinstance(principals, str):
            subject_match = _match_pattern(principals, subject)
    # Return True if all checks pass
    return action_match and resource_match and subject_match

def count_matching_policies_ignore_effect(
    subject: str | dict[str, ...],
    resource: str | dict[str, ...],
    action: str,
    policies: list[str] | list[dict[str, ...]],
) -> int:
    """Return the number of policies that match the request, ignoring whether they allow or deny."""
    count = 0
    for policy in policies:
        if isinstance(policy, str):
            try:
                policy_doc = json.loads(policy)
            except json.JSONDecodeError:
                continue
        else:
            policy_doc = policy
        statements = policy_doc.get("Statement", [])
        if isinstance(statements, dict):
            statements = [statements]
        for stmt in statements:
            if _check_statement(stmt, subject, resource, action):
                count += 1
                break  # one matching statement is enough for this policy
    return count

def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    """Return True if at least one policy matches the request, ignoring whether it allows or denies."""
    return count_matching_policies_ignore_effect(subject, resource, action, policies) > 0
