def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    """
    Return True if at least one policy matches the request,
    ignoring whether the policy allows or denies.
    """
    def matches_pattern(value: str, pattern: str) -> bool:
        """Check if value matches a wildcard pattern (supports * and ?)."""
        return fnmatch.fnmatch(value, pattern)

    def statement_matches(stmt: dict, subject: str, action: str, resource: str) -> bool:
        """Check if a statement applies to the given subject, action, resource."""
        # Check principal (subject)
        principal = stmt.get("Principal")
        if principal is not None:
            # Principal can be a dict like {"AWS": "arn:..."} or a string "*"
            if isinstance(principal, dict):
                # For simplicity, assume Principal has a key "AWS"
                principal_vals = principal.get("AWS", "")
                if isinstance(principal_vals, str):
                    principal_vals = [principal_vals]
                if not any(matches_pattern(subject, p) for p in principal_vals):
                    return False
            else:
                # String (e.g., "*")
                if not matches_pattern(subject, principal):
                    return False

