def solve(subject: str, resource: str, action: str, policies: list[str]) -> list[str]:
    # Helper to parse subject string (format: role/department/level)
    def parse_subject(s: str) -> dict:
        parts = s.split('/')
        return {'role': parts[0], 'department': parts[1], 'level': parts[2]}

    # Helper to parse resource string (format: type:sensitivity:owner)
    def parse_resource(s: str) -> dict:
        parts = s.split(':')
        return {'type': parts[0], 'sensitivity': parts[1], 'owner': parts[2]}

    # Generate audit log string including decision
    def audit_log(subj_str: str, res_str: str, act: str, decision: bool) -> str:
        subj = parse_subject(subj_str)
        res = parse_resource(res_str)
        decision_str = "granted" if decision else "denied"
        return (
            f"[{subj['role']}/{subj['department']}/L{subj['level']}] "
            f"{act} {res['type']}:{res['sensitivity']}:{res['owner']} -> {decision_str}"
        )

    # Determine the next more privileged action using the provided priority function
    valid_actions = {'read', 'write', 'delete', 'admin'}
    if action not in valid_actions:
        raise ValueError(f"Invalid action: {action!r}")

    priorities = {a: action_priority_swapped(a) for a in valid_actions}
    # Sorted by priority ascending: admin (1), delete (2), write (3), read (4)
    sorted_actions = sorted(valid_actions, key=lambda a: priorities[a])
    idx = sorted_actions.index(action)

    actions_to_eval = [action]
    if idx > 0:  # there is a more privileged action
        actions_to_eval.append(sorted_actions[idx - 1])

    result = []
    for a in actions_to_eval:
        decision = authorize_allow_all(subject, resource, a, policies)
        result.append(audit_log(subject, resource, a, decision))
    return result
