import json

def solve(subject: str, resources: list[str], policies: list[str]) -> dict:
    def authorize(
        subject: str,
        resource: str,
        action: str,
        policies: list[str],
        default: bool = False
    ) -> bool:
        decisions = []
        for policy in policies:
            # Try to parse as JSON object, otherwise treat as simple CSV
            if isinstance(policy, str):
                try:
                    pol = json.loads(policy)
                except json.JSONDecodeError:
                    parts = policy.split(',')
                    if len(parts) != 4:
                        continue
                    pol = {
                        'subject': parts[0].strip(),
                        'resource': parts[1].strip(),
                        'action': parts[2].strip(),
                        'effect': parts[3].strip()
                    }
            else:
                pol = policy

            # Check if policy matches (wildcard '*' matches anything)
            subj_match = pol.get('subject') in (subject, '*')
            res_match = pol.get('resource') in (resource, '*')
            act_match = pol.get('action') in (action, '*')
            if subj_match and res_match and act_match:
                effect = pol.get('effect', 'allow')
                decisions.append(effect == 'allow')

        if not decisions:
            return default
        # Explicit deny overrides any allow
        if False in decisions:
            return False
        return True

    total = len(resources)
    allowed = sum(
        1 for resource in resources
        if authorize(subject, resource, 'read', policies)
    )
    denied = total - allowed
    return {'total': total, 'allowed': allowed, 'denied': denied}
