def solve(series: str) -> float:
    # Parse the input string as a JSON array of numbers
    try:
        values = json.loads(series)
    except (json.JSONDecodeError, TypeError):
        # Fallback: try to parse as comma-separated list
        if ',' in series:
            values = [float(x.strip()) for x in series.strip('[]').split(',')]
        else:
            # Single number
            values = [float(series.strip('[]'))]

    if not values:
        return 0.0

    n = len(values)
    mean = sum(values) / n
    variance = sum((x - mean) ** 2 for x in values) / n
    std = math.sqrt(variance)

    if std == 0.0:
        return 0.0

    z_scores = [(x - mean) / std for x in values]
    return max(abs(z) for z in z_scores)
