import json
import statistics
import re

def parse_series(s: str) -> list[float]:
    # Try JSON first
    try:
        data = json.loads(s)
        if isinstance(data, list):
            return [float(x) for x in data]
        elif isinstance(data, dict) and 'values' in data:
            return [float(x) for x in data['values']]
    except:
        pass
    # Fallback: extract all numbers using regex
    nums = re.findall(r'-?\d+\.?\d*(?:[eE][+-]?\d+)?', s)
    return [float(x) for x in nums]

def solve(series_list: list[str]) -> int:
    count = 0
    for s in series_list:
        values = parse_series(s)
        if not values:
            continue
        n = len(values)
        mean = statistics.mean(values)
        if n > 1:
            std = statistics.pstdev(values)
        else:
            std = 0.0
        if std == 0:
            continue
        for v in values:
            if (v - mean) / std > 0:
                count += 1
    return count

